using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(b =>
        {
            // Breaking change 1: Discriminator property renamed from "Discriminator" to "$type".
            // Keep the old name so existing documents and raw SQL
            // (SELECT * FROM c WHERE c.Discriminator = 'Blog') continue to work.
            b.HasDiscriminator<string>("Discriminator");

            // Breaking change 2: id no longer includes the discriminator prefix.
            // EF Core 8 stored id as "Blog|<key>"; EF Core 9 uses just "<key>".
            // A value converter preserves the old format for existing documents.
            b.Property(e => e.Id)
                .HasConversion(
                    v => "Blog|" + v,
                    v => v.StartsWith("Blog|") ? v.Substring(5) : v);
        });

        // Breaking change 3: HasIndex() is not supported by the Cosmos provider
        // and now throws at model build time. Removed.
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

